""""This script holds the Validator Threshold functionality.Essentially, it takes the output of metrics calculation (in .csv) and compares its outputs against thresholds defined in configs/configs.py"""import sysimport ossys.path.append(os.path.abspath(os.path.join(os.path.dirname(__file__), "..", "..")))from src.dq_framework.utils.dq_utils import generate_log_starting_message, generate_log_success_message, generate_log_error_messagefrom utils.dq_utils import setup_logger, format_date_loggerfrom configs.framework import PLUMBLINE_LOG_DIR, THRESHOLD_VALIDATOR_LABELSfrom typing import Dict, Tuple, Anyimport mathimport sysimport pandas as pddef validate_thresholds_automatic(in_results: Dict[str, Any], in_dq_dimension: str, in_instrument_configs: dict) -> Dict[str, Tuple[str, float, float, float, float]]:    """    Validates a dictionary of sensor quality metrics against pre-configured thresholds    for the 'automatic' read mode of a given Data Quality (DQ) dimension.    Each metric is checked against its corresponding threshold and classified as:    - "OK" if within threshold    - "WARNING" if above threshold but below threshold × limit_factor    - "ALERT" if above threshold × limit_factor    - "NO THRESHOLD" if no threshold is defined    - "NO VALUE" if the metric value is None or non-numeric    For percentage-based metrics (ending with '_prctg'), thresholds are interpreted    as percent values and converted to fractional form (divided by 100) before comparison.    Args:        in_results (Dict[str, Any]): Dictionary of {metric_name: value} for a DQ dimension.        in_dq_dimension (str): Name of the DQ dimension (e.appendix_g., 'Completeness', 'Timeliness').        in_instrument_configs (dict): Configuration dictionary containing threshold values and limit_factor.    Returns:        Dict[str, Tuple[str, float, float, float, float]]:            Dictionary mapping each metric to a tuple:                (                    status,                    value,                    threshold,                    absolute_difference,                    deviation_percentage                )    """    logger = setup_logger(PLUMBLINE_LOG_DIR)    logger_module = f"THRESHOLD VALIDATOR"    logger_module_info = f"RUNNING THRESHOLD VALIDATOR - THRESHOLD VALIDATOR AUTOMATIC READINGS"    logger_starter_message = f"Running Threshold Validator for Automatic readings"    logger_success_message = f"Dictionary saved in memory"    try:        logger.info(generate_log_starting_message(logger_module, logger_module_info, logger_starter_message))        classified_result: Dict[str, Tuple[str, float, float, float, float]] = {}        # Obter config da dimensão e modo (lança KeyError se não existir)        thresholds_configs = in_instrument_configs["threshold_validator"][in_dq_dimension]["automatic"]        limit_factor = thresholds_configs["limit_factor"]        for raw_metric, raw_value in in_results.items():            metric = str(raw_metric).strip()            value = raw_value            # Normalizar 'value' para float quando possível            try:                if value is None or (isinstance(value, float) and math.isnan(value)):                    # Valor ausente                    classified_result[metric] = ("NO VALUE", value, None, None, None)                    continue                value = float(value)            except Exception:                # Se não for convertível para float, registar e saltar                logger.warning("\t[WARN]\t[THRESHOLD VALIDATOR]\t" + format_date_logger() +                               f"\tMetric {metric}: value '{raw_value}' is not numeric. Skipping.")                classified_result[metric] = ("NO VALUE", raw_value, None, None, None)                continue            # Obter threshold configurado (pode ser None)            threshold = thresholds_configs.get(metric, None)            if threshold is None:                classified_result[metric] = ("NO THRESHOLD", value, None, None, None)                continue            # Lidar com métricas percentuais            is_percent_metric = metric.endswith("_prctg")            # Interpretar threshold_cfg: pode estar em formato percentual (e.appendix_g., 1 ou 100) ou fraccional (0.01)            #threshold_used = float(threshold)            abs_diff = round(abs(value - threshold), 8)            if is_percent_metric:                # Se threshold > 1, assumimos que está expresso como percentagem (ex: 100 ou 1)                # - se threshold >= 1 e <= 100 -> interpretamos como percentagem (dividimos por 100)                # - se threshold > 100 -> também é percentagem (dividimos por 100)                # if threshold_used > 1:                #     threshold_used = threshold_used / 100.0                threshold = threshold / 100                # Métrica percentual → diferença em pontos percentuais                deviation_pct = str(round((value - threshold) * 100, 2))            # Para métricas absolutas, mantemos threshold_used tal como está.            # Calcular diferença absoluta (em unidades da métrica)            else:                # Métrica absoluta → diferença relativa (%)                if threshold == 0 and value == 0:                    deviation_pct = 0                elif threshold == 0 and value != 0:                    deviation_pct = str(0.0) if value == str(0) else str(100.0)                else:                    deviation_pct = str(round(((value - threshold) / threshold) * 100, 2))            # Classificação usando limit_factor (mesma lógica para percentuais e absolutos)            try:                if value <= threshold:                    status = "OK"                elif value <= threshold * limit_factor:                    status = "WARNING"                else:                    status = "ALERT"            except Exception:                status = "NO THRESHOLD"            classified_result[metric] = (status, value, threshold, abs_diff, deviation_pct)        logger.info(generate_log_success_message(logger_module, logger_module_info, logger_success_message))        return classified_result    except KeyError as e:        logger.error("\t[ERROR]\t[THRESHOLD VALIDATOR]\t" + format_date_logger() +                     f"\tConfiguration missing for dimension/mode: {e}")        raise    except Exception as e:        logger.error("\t[ERROR]\t[THRESHOLD VALIDATOR]\t" + format_date_logger() +                     f"\tUnhandled error during threshold validation: {e}")        sys.exit(1)def validate_thresholds_manual(in_results: Dict[str, Any], in_dq_dimension: str, in_instrument_configs: dict) -> Dict[str, Tuple[str, float, float, float, float]]:    """    Validates a dictionary of sensor quality metrics against pre-configured thresholds    for the 'manual' read mode of a given Data Quality (DQ) dimension.    This function follows the same logic as `validate_thresholds_automatic`, but uses the    thresholds defined for manual data acquisition.    Each metric is classified into one of the following:    - "OK" if within threshold    - "WARNING" if above threshold but below threshold × limit_factor    - "ALERT" if above threshold × limit_factor    - "NO THRESHOLD" if no threshold is defined    - "NO VALUE" if the metric value is None or non-numeric    Args:        in_results (Dict[str, Any]): Dictionary of {metric_name: value} for a DQ dimension.        in_dq_dimension (str): Name of the DQ dimension (e.appendix_g., 'Timeliness').        in_instrument_configs (dict): Configuration dictionary containing threshold values and limit_factor.    Returns:        Dict[str, Tuple[str, float, float, float, float]]:            Dictionary mapping each metric to a tuple:                (                    status,                    value,                    threshold,                    absolute_difference,                    deviation_percentage                )    """    logger = setup_logger(PLUMBLINE_LOG_DIR)    logger_module = f"THRESHOLD VALIDATOR"    logger_module_info = f"RUNNING THRESHOLD VALIDATOR - THRESHOLD VALIDATOR MANUAL READINGS"    logger_starter_message = f"Running Threshold Validator for Automatic readings"    logger_success_message = f"Dictionary saved in memory"    try:        logger.info(generate_log_starting_message(logger_module, logger_module_info, logger_starter_message))        classified_result: Dict[str, Tuple[str, float, float, float, float]] = {}        # Obter config da dimensão e modo (lança KeyError se não existir)        thresholds_configs = in_instrument_configs["threshold_validator"][in_dq_dimension]["manual"]        limit_factor = thresholds_configs["limit_factor"]        for raw_metric, raw_value in in_results.items():            metric = str(raw_metric).strip()            value = raw_value            # Normalizar 'value' para float quando possível            try:                if value is None or (isinstance(value, float) and math.isnan(value)):                    # Valor ausente                    classified_result[metric] = ("NO VALUE", value, None, None, None)                    continue                value = float(value)            except Exception:                # Se não for convertível para float, registar e saltar                logger.warning("\t[WARN]\t[THRESHOLD VALIDATOR]\t" + format_date_logger() +                               f"\tMetric {metric}: value '{raw_value}' is not numeric. Skipping.")                classified_result[metric] = ("NO VALUE", raw_value, None, None, None)                continue            # Obter threshold configurado (pode ser None)            threshold = thresholds_configs.get(metric, None)            if threshold is None:                classified_result[metric] = ("NO THRESHOLD", value, None, None, None)                continue            # Lidar com métricas percentuais            is_percent_metric = metric.endswith("_prctg")            # Interpretar threshold_cfg: pode estar em formato percentual (e.appendix_g., 1 ou 100) ou fraccional (0.01)            #threshold_used = float(threshold)            abs_diff = round(abs(value - threshold), 8)            if is_percent_metric:                # Se threshold > 1, assumimos que está expresso como percentagem (ex: 100 ou 1)                # - se threshold >= 1 e <= 100 -> interpretamos como percentagem (dividimos por 100)                # - se threshold > 100 -> também é percentagem (dividimos por 100)                # if threshold_used > 1:                #     threshold_used = threshold_used / 100.0                threshold = threshold / 100                # Métrica percentual → diferença em pontos percentuais                deviation_pct = str(round((value - threshold) * 100, 2))            # Para métricas absolutas, mantemos threshold_used tal como está.            # Calcular diferença absoluta (em unidades da métrica)            else:                # Métrica absoluta → diferença relativa (%)                if threshold == 0 and value == 0:                    deviation_pct = 0                elif threshold == 0 and value != 0:                    deviation_pct = str(0.0) if value == str(0) else str(100.0)                else:                    deviation_pct = str(round(((value - threshold) / threshold) * 100, 2))            # Classificação usando limit_factor (mesma lógica para percentuais e absolutos)            try:                if value <= threshold:                    status = "OK"                elif value <= threshold * limit_factor:                    status = "WARNING"                else:                    status = "ALERT"            except Exception:                status = "NO THRESHOLD"            classified_result[metric] = (status, value, threshold, abs_diff, deviation_pct)        logger.info(generate_log_success_message(logger_module, logger_module_info, logger_success_message))        return classified_result    except Exception as e:        logger.error(generate_log_error_message(logger_module, logger_module_info, e))        sys.exit(1)    except Exception as e:        logger.error(generate_log_error_message(logger_module, logger_module_info, e))        sys.exit(1)def save_thresholdvalidator_results_to_csv(in_classified_result: Dict[str, Tuple[str, float]], in_dq_dimension: str, in_plumbline_id: str, in_output_results_dir: str, in_read_mode:str, in_year:int) -> None:    """    Saves the results of threshold validation to a CSV file.    Takes the dictionary of classified results from `validate_thresholds_*` functions    and generates a structured file including classification status, values, thresholds,    absolute differences, and deviation percentages.    The CSV includes metadata (plumbline ID, year, read mode, DQ dimension) and is saved    in the specified output directory.    Args:        in_classified_result (Dict[str, Tuple[str, float, float, float, float]]):            Output from the threshold validation function.        in_dq_dimension (str): The DQ dimension name (e.appendix_g., 'Completeness').        in_plumbline_id (str): Identifier of the joint/plumbline sensor.        in_output_results_dir (str): Path to directory where CSV file should be saved.        in_read_mode (str): Reading mode ('automatic' or 'manual').        in_year (int): Year of the data being analyzed.    Returns:        None    Output:        A CSV file named:            `ThresholdValidator_<dimension>_<read_mode>_<year>_<plumbline_id>.csv`        is saved in the specified output directory with the following columns:            - plumbline_id            - year            - read_mode            - dq_dimension            - metric            - status            - value            - threshold            - threshold_diff            - threshold_deviation_pct    """    logger = setup_logger(PLUMBLINE_LOG_DIR)    logger_module = f"THRESHOLD VALIDATOR"    logger_module_info = f"THRESHOLD VALIDATOR - SAVE .CSV"    logger_starter_message = f"Saving Threshold Validator .csv for - Sensor#{in_plumbline_id} ({in_year}, {in_read_mode} readings) - {in_dq_dimension} Dimension"    file_filename = f"ThresholdValidator_{in_dq_dimension}_{in_read_mode}_{in_year}_{in_plumbline_id}.csv"    full_file_path = os.path.join(in_output_results_dir, file_filename)    logger_success_message = f"csv saved in: {in_output_results_dir}"    try:        logger.info(generate_log_starting_message(logger_module, logger_module_info, logger_starter_message))        df = pd.DataFrame([            {"metric": metric, "status": status, "value": value, "threshold": threshold, "threshold_diff": threshold_difference,"threshold_deviation_pct": threshold_deviation_pct}            for metric, (status, value, threshold, threshold_difference, threshold_deviation_pct) in in_classified_result.items()        ])        df.insert(0, "dq_dimension", in_dq_dimension)        df.insert(0, "read_mode", in_read_mode)        df.insert(0, "year", in_year)        df.insert(0, "plumbline_id", in_plumbline_id)        df["status"] = pd.Categorical(df["status"], categories=THRESHOLD_VALIDATOR_LABELS, ordered=True)        # Ordenar        df = df.sort_values(by=["status", "metric"], ascending=[True, True])        os.makedirs(in_output_results_dir, exist_ok=True)        df.to_csv(full_file_path, index=False, sep=";")        logger.info(generate_log_success_message(logger_module, logger_module_info, logger_success_message))    except Exception as e:        logger.error(generate_log_error_message(logger_module, logger_module_info, e))        sys.exit(1)